#!/bin/bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-05-29

# Regression guard for #1796.
#
# build-plugins.sh must reinstall src/mcp-server deps when the lockfile CHANGES,
# not only when node_modules is absent. The old `[[ ! -d node_modules ]]`-only
# guard skipped `npm ci` on a warm checkout after a Dependabot bump, so esbuild
# bundled STALE deps and the committed plugins/ork/mcp-server/server.mjs drifted
# from a fresh CI build (CI always installs into a clean tree) — failing the
# `git diff --quiet plugins/` drift gate on any rebuild-forcing PR.

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="$(cd "$SCRIPT_DIR/../.." && pwd)"
BUILD="$PROJECT_ROOT/scripts/build-plugins.sh"

RED='\033[0;31m'
GREEN='\033[0;32m'
NC='\033[0m'
PASS=0
FAIL=0
log_pass() { echo -e "  ${GREEN}PASS${NC} $1"; PASS=$((PASS + 1)); }
log_fail() { echo -e "  ${RED}FAIL${NC} $1 — $2"; FAIL=$((FAIL + 1)); }

echo "Build mcp-server fresh-deps guard (#1796)"
echo "========================================="

# Portable lockfile hash (Linux sha256sum, macOS shasum) — mirrors build-plugins.sh.
hash_file() {
  if command -v sha256sum > /dev/null 2>&1; then
    sha256sum "$1" | cut -d' ' -f1
  else
    shasum -a 256 "$1" | cut -d' ' -f1
  fi
}

# 1. Structural: the lockfile-hash stamp gating must be present in the script.
if grep -q 'ork-lockhash' "$BUILD" && grep -q 'lock_hash' "$BUILD"; then
  log_pass "build-plugins.sh gates mcp-server install on a lockfile-hash stamp"
else
  log_fail "lockfile gating absent" "no .ork-lockhash / lock_hash guard — regressed to the bare node_modules check?"
fi

# 2. Behavioral: replicate the exact install-decision and assert all 3 states.
#    decide() returns "reinstall" or "skip" given a stamp + current lockfile.
TMP="$(mktemp -d)"
trap 'rm -rf "$TMP"' EXIT
printf '{"v":1}\n' > "$TMP/package-lock.json"
mkdir -p "$TMP/node_modules"
LOCK_HASH="$(hash_file "$TMP/package-lock.json")"
STAMP="$TMP/node_modules/.ork-lockhash"

decide() {
  local sv=""
  [[ -f "$STAMP" ]] && sv="$(cat "$STAMP")"
  if [[ ! -d "$TMP/node_modules" ]] || [[ "$sv" != "$LOCK_HASH" ]]; then echo "reinstall"; else echo "skip"; fi
}

# State A: warm node_modules, no stamp (first build after this fix lands).
if [ "$(decide)" = "reinstall" ]; then
  log_pass "warm node_modules + no stamp → reinstall"
else
  log_fail "no-stamp state" "expected reinstall"
fi

# State B: stamp matches current lockfile → skip (fast warm rebuild).
printf '%s\n' "$LOCK_HASH" > "$STAMP"
if [ "$(decide)" = "skip" ]; then
  log_pass "stamp matches lockfile → skip (no needless npm ci)"
else
  log_fail "match state" "expected skip"
fi

# State C: lockfile bumped (stamp now stale) → reinstall. THE #1796 case.
printf '{"v":2,"dep":"bumped"}\n' > "$TMP/package-lock.json"
LOCK_HASH="$(hash_file "$TMP/package-lock.json")"
if [ "$(decide)" = "reinstall" ]; then
  log_pass "lockfile bumped, stamp stale → reinstall (the #1796 fix)"
else
  log_fail "bumped state" "expected reinstall — this is the bug #1796 fixes"
fi

echo ""
echo "========================================="
echo "  Results: $PASS passed, $FAIL failed"
echo "========================================="
[ "$FAIL" -gt 0 ] && { echo -e "${RED}FAIL${NC}"; exit 1; }
echo -e "${GREEN}SUCCESS${NC}"
